mapper.select:
SELECT o.id, o.inbound_no, o.source_type, o.source_id, o.supplier_id, CASE WHEN sup.status = 'disabled' THEN CONCAT(o.supplier_name, ' [禁用]') WHEN sup.status = 'cancelled' THEN CONCAT(o.supplier_name, ' [已注销]') ELSE o.supplier_name END AS supplier_name, o.source_order_id, o.source_order_no, o.org_id, o.receiving_org_id, rorg.org_name AS receiving_org_name, o.warehouse_id, w.warehouse_name, (SELECT GROUP_CONCAT(DISTINCT w2.warehouse_name SEPARATOR '、') FROM wms_inbound_order_item i2 LEFT JOIN wms_warehouse w2 ON w2.id = i2.warehouse_id AND w2.deleted = 0 WHERE i2.inbound_id = o.id) AS warehouse_names, o.total_amount, o.remark, o.attachments, o.status, o.version, o.post_status, o.post_error_message, o.submitted_at, o.submitted_by, o.submitter_name, o.approved_at, o.approve_remark, o.created_at, o.updated_at, COUNT(i.id) AS item_count FROM wms_inbound_order o LEFT JOIN scm_supplier sup ON sup.id = o.supplier_id AND sup.deleted = 0 LEFT JOIN wms_warehouse w ON w.id = o.warehouse_id AND w.deleted = 0 LEFT JOIN sys_organization rorg ON rorg.id = o.receiving_org_id AND rorg.deleted = 0 LEFT JOIN wms_inbound_order_item i ON i.inbound_id = o.id WHERE o.deleted = 0
AND o.org_id = #{q.orgId}
AND o.org_id IN
#{oid}
AND 1 = 0
AND o.inbound_no LIKE CONCAT('%', #{q.inboundNo}, '%')
AND o.warehouse_id = #{q.warehouseId}
AND o.source_type = #{q.sourceType}
AND (o.status = 'completed' OR (o.status = 'approved' AND o.post_status = 'posted'))
AND o.status = 'approved' AND COALESCE(NULLIF(TRIM(o.post_status), ''), 'unposted') <> 'posted'
AND o.status = #{q.status}
AND DATE(o.created_at) >= #{q.startDate}
AND DATE(o.created_at) <= #{q.endDate}
GROUP BY o.id ORDER BY o.created_at DESC

SELECT COALESCE(SUM(CASE WHEN o.created_at >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND o.created_at < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) THEN 1 ELSE 0 END), 0) AS thisMonthTotalCount, COALESCE(SUM(CASE WHEN o.status = 'pending' AND o.created_at >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND o.created_at < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) THEN 1 ELSE 0 END), 0) AS thisMonthPendingCount, COALESCE(SUM(CASE WHEN o.status = 'approved' AND COALESCE(NULLIF(TRIM(o.post_status), ''), 'unposted') <> 'posted' AND o.created_at >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND o.created_at < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) THEN 1 ELSE 0 END), 0) AS thisMonthApprovedCount, COALESCE(SUM(CASE WHEN (o.status = 'completed' OR (o.status = 'approved' AND o.post_status = 'posted')) AND o.created_at >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND o.created_at < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH) THEN COALESCE(o.total_amount, 0) ELSE 0 END), 0) AS thisMonthInboundAmount FROM wms_inbound_order o WHERE o.deleted = 0
AND o.org_id = #{q.orgId}
AND o.org_id IN
#{oid}
AND 1 = 0

SELECT EXISTS (
    SELECT 1
    FROM wms_inbound_order
    WHERE deleted = 0
      AND warehouse_id = #{warehouseId}
      AND status IN
      #{status}
)

SELECT EXISTS (
    SELECT 1
    FROM wms_inbound_order
    WHERE warehouse_id = #{warehouseId}
)
